+    });
+    api.registerImageGenerationProvider(buildComfyImageGenerationProvider());
+    api.registerVideoGenerationProvider(buildComfyVideoGenerationProvider());
+    api.registerTool(createComfyMusicGenerateTool(api));
+  },
+});

